import React, { useEffect, useState } from "react";
import Header from "./components/public/Header";
import ProductCard from "./components/public/ProductCard";
import Cart from "./components/public/Cart";
import Footer from "./components/public/Footer";
import './styles.css';

export default function App() {
  const [zapatillas, setZapatillas] = useState([]);
  const [cart, setCart] = useState([]);

  useEffect(() => {
    fetch("http://localhost:8080/zapatillas")
      .then((res) => res.json())
      .then(setZapatillas);
  }, []);

  const addToCart = (zapatilla) => {
    setCart([...cart, zapatilla]);
  };

  const handlePurchase = () => {
    cart.forEach((z) => {
      fetch(`http://localhost:8080/zapatillas/vender/${z.id}`, {
        method: "PUT",
      });
    });

    // Limpiar carrito y actualizar stock/ventas localmente
    setZapatillas(
      zapatillas.map((z) => {
        const itemsSold = cart.filter((c) => c.id === z.id).length;
        return itemsSold > 0
          ? {
              ...z,
              cantidad: z.cantidad - itemsSold,
              ventas: z.ventas + itemsSold,
            }
          : z;
      })
    );

    setCart([]);
  };
  const removeFromCart = (id) => {
    const index = cart.findIndex((item) => item.id === id);
    if (index !== -1) {
      const updatedCart = [...cart];
      updatedCart.splice(index, 1);
      setCart(updatedCart);
    }
  };

  return (
    <div className="flex flex-col min-h-screen bg-gray-100">
      <Header />
      <main className="flex flex-col md:flex-row flex-grow">
        {/* Catálogo de productos */}
        <section className="flex-1 p-4 grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-4">
          {zapatillas.map((z) => (
            <ProductCard key={z.id} zapatilla={z} addToCart={addToCart} />
          ))}
        </section>

        {/* Carrito */}
        <Cart cart={cart} handlePurchase={handlePurchase} />
      </main>
      <Footer />
    </div>
  );
}
